import { useState } from "react";
import Card from "../components/ui/Card";
import Select from "../components/ui/select";
import Btn from "../components/ui/Btn";

const AssignModal = ({ student, rooms, onConfirm, onClose }) => {
  const [roomId, setRoomId] = useState("");
  const availableRooms = rooms.filter(r => r.occupants.length < r.capacity);
  
  return (
    <div style={{ 
      position: "fixed", top: 0, left: 0, right: 0, bottom: 0, 
      background: "rgba(0,0,0,0.5)", display: "flex", 
      alignItems: "center", justifyContent: "center", zIndex: 1000 
    }}>
      <Card style={{ maxWidth: 400, width: "90%" }}>
        <h3>Assign Room to {student?.name}</h3>
        <Select value={roomId} onChange={e => setRoomId(e.target.value)}>
          <option value="">Select a room</option>
          {availableRooms.map(r => (
            <option key={r.id} value={r.id}>
              {r.id} - {r.type} ({r.capacity - r.occupants.length} slots)
            </option>
          ))}
        </Select>
        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", marginTop: 20 }}>
          <Btn variant="ghost" onClick={onClose}>Cancel</Btn>
          <Btn onClick={() => roomId && onConfirm(student.id, roomId)} disabled={!roomId}>Confirm</Btn>
        </div>
      </Card>
    </div>
  );
};

export default AssignModal;
